def is_anagram(str1, str2):
    # If the strings have a different number of characters, they cannot be anagrams
    if len(str1) != len(str2):
        return False

    # Create a dictionary to count the number of characters in each string
    char_count = {}

    # Count the characters in the first string
    for char in str1:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    # Subtract the characters in the second string
    for char in str2:
        if char in char_count:
            char_count[char] -= 1
        else:
            return False

    # If any of the values in the char_count dictionary are not 0, then the strings are not anagrams
    for value in char_count.values():
        if value != 0:
            return False

    return True
